1	type Customer = {
2	  yearsAsCustomer: number;
3	  quoteCount: number;
4	};
5	
6	type Item = {
7	  type: string;
8	  material: string;
9	  enchantment: number;
10	  cursed: boolean;
11	};
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_RATE = 0.1;
24	
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PREMIUM = 60;
27	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
28	
29	const componentPremium = (type: string, count: number): number =>
30	  count === COMPONENT_BLOCK_SIZE
31	    ? COMPONENT_BLOCK_PREMIUM
32	    : count * BASE_PREMIUMS[type];
33	
34	export function quote(customer: Customer, items: Item[]): number {
35	  if (items.length === 0) return PROCESSING_FEE;
36	
37	  let basePremium = 0;
38	  const componentCounts: Record<string, number> = {};
39	
40	  for (const item of items) {
41	    if (COMPONENT_TYPES.has(item.type)) {
42	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
43	    } else {
44	      basePremium += BASE_PREMIUMS[item.type];
45	    }
46	  }
47	
48	  for (const type of Object.keys(componentCounts)) {
49	    basePremium += componentPremium(type, componentCounts[type]);
50	  }
51	
52	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
53	  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
54	}
55	
56	export function claim() {
57	  return undefined;
58	}
